import{_ as t,o as r,c as o,ah as a}from"./chunks/framework.ojwJKwrc.js";const p=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),i={name:"guide/introduction.md"};function n(s,e,l,d,c,u){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Celox is a JIT (Just-In-Time) simulator for <a href="https://veryl-lang.org/" target="_blank" rel="noreferrer">Veryl HDL</a>. It lowers Veryl designs through Celox&#39;s simulation IR and compiles them to executable code. On x86-64, Celox uses its own native backend by default; on other targets, it falls back to <a href="https://cranelift.dev/" target="_blank" rel="noreferrer">Cranelift</a>.</p><div class="tip custom-block"><p class="custom-block-title">Try it in your browser</p><p>The <a href="https://celox-sim.github.io/celox/playground/" target="_blank" rel="noreferrer">Celox Playground</a> lets you write Veryl modules and run simulations directly in the browser -- no installation required.</p></div><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><ul><li><strong>JIT Compilation</strong> -- Veryl designs are compiled through a multi-stage pipeline (Veryl → SLT → SIR → native code) for near-native execution speed.</li><li><strong>Native x86-64 Backend</strong> -- On x86-64, Celox uses its own code generator for the fastest simulation throughput.</li><li><strong>Cranelift Fallback</strong> -- On ARM, RISC-V, and other non-x86-64 targets, Celox can still JIT-compile and run designs.</li><li><strong>Event-Driven Scheduling</strong> -- An event-driven scheduler with multi-clock domain support handles complex timing interactions.</li><li><strong>4-State Simulation</strong> -- IEEE 1800-compliant 4-state value representation with proper X propagation.</li><li><strong>TypeScript Testbenches</strong> -- Write testbenches in TypeScript with type-safe signal access and modern developer tooling.</li><li><strong>VCD Waveform Output</strong> -- Generate VCD files for waveform inspection with standard viewers.</li></ul><h2 id="project-structure" tabindex="-1">Project Structure <a class="header-anchor" href="#project-structure" aria-label="Permalink to &quot;Project Structure&quot;">​</a></h2><p>Celox is organized as a Rust + TypeScript workspace:</p><table tabindex="0"><thead><tr><th>Crate / Package</th><th>Description</th></tr></thead><tbody><tr><td><code>crates/celox</code></td><td>Core simulator (IR, native x86-64 backend, Cranelift JIT, runtime)</td></tr><tr><td><code>crates/celox-macros</code></td><td>Procedural macros</td></tr><tr><td><code>crates/celox-napi</code></td><td>N-API bindings for Node.js</td></tr><tr><td><code>crates/celox-ts-gen</code></td><td>TypeScript type generation library</td></tr><tr><td><code>packages/celox</code></td><td>TypeScript runtime package</td></tr><tr><td><code>packages/vite-plugin</code></td><td>Vite / Vitest plugin for typed <code>.veryl</code> imports</td></tr></tbody></table><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li><strong>Frontend</strong> -- The Veryl source is analyzed and lowered into module hierarchy, signals, events, and combinational / sequential blocks.</li><li><strong>Middle-end</strong> -- The logic is transformed through SLT and SIR, then optimized for simulation.</li><li><strong>Backend</strong> -- On x86-64, Celox emits native machine code directly. On other targets, it uses Cranelift JIT as the fallback execution backend.</li></ol><p>For a deeper look at the architecture, see the <a href="./../internals/architecture.html">Architecture</a> internals document.</p>',11)])])}const g=t(i,[["render",n]]);export{p as __pageData,g as default};
